```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::Reader reader(buffer);
    NetworkPacket packet;

    // Read packet_id
    packet.packet_id = reader.read<uint32_t>();

    // Read username with length prefix
    packet.username = reader.read_prefixed_string<uint32_t>();

    // Read scores vector using read_container
    packet.scores = reader.read_container<uint32_t, uint32_t>();

    // Read metadata as null-terminated string for zero-copy
    packet.metadata = reader.read_string_null();

    // Skip any remaining padding bytes
    reader.skip_to_end();

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::Reader reader(buffer);
    PacketInfo info;

    // Use span() for packet_id (first 4 bytes)
    auto packet_id_span = reader.span(sizeof(uint32_t));
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());

    // Skip packet_id bytes since we already read them via span
    reader.skip(sizeof(uint32_t));

    // Read username using prefixed adaptor to get string_view
    info.username = reader.read_prefixed_string_view<uint32_t>();

    // Skip scores vector: read count first, then skip the data
    uint32_t score_count = reader.read<uint32_t>();
    reader.skip(score_count * sizeof(uint32_t));

    return info;
}
```

Key implementation details:

1. **`deserialize_packet`**:
   - Uses `hexi::Reader` to sequentially read data from the buffer
   - `read<uint32_t>()` for the packet_id
   - `read_prefixed_string<uint32_t>()` for username with length prefix
   - `read_container<uint32_t, uint32_t>()` for the scores vector (first uint32_t for count, second for element type)
