#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span() to read header with zero-copy
    auto header_span = buffer.subspan(0, sizeof(PacketHeader));

    // Create a zero-copy view of the header data
    auto header_view = std::span<const uint8_t, sizeof(PacketHeader)>(
        header_span.data(), sizeof(PacketHeader));

    // Extract fields from the header using zero-copy operations
    PacketHeader header;
    header.version = header_view[0];
    header.flags = header_view[1];
    // Combine two bytes for packet_id (assuming little-endian)
    header.packet_id = static_cast<uint16_t>(header_view[2]) | 
                      (static_cast<uint16_t>(header_view[3]) << 8);

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use view() to read null-terminated string with zero-copy
    // Find the null terminator
    const uint8_t* start = buffer.data();
    const uint8_t* end = start;

    // Search for null terminator
    while (end < start + buffer.size() && *end != 0) {
        ++end;
    }

    // If we found a null terminator, create a string_view of the message
    if (end < start + buffer.size()) {
        // Calculate length and create zero-copy string view
        size_t length = end - start;
        return std::string_view(reinterpret_cast<const char*>(start), length);
    }

    // If no null terminator found, return empty view or entire buffer
    // For safety, return empty view
    return std::string_view();
}
```

