#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator for integers
    block_allocator<int, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Demonstrate initial state
    std::cout << "1. Initial state:\n";
    std::cout << "   - Free list contains all " << element_count << " blocks\n";
    std::cout << "   - Each deallocation would push() blocks to free list head\n";
    std::cout << "   - Each allocation would pop() blocks from free list head\n\n";

    // Allocate some blocks to show pop() behavior
    int* blocks[element_count];
    size_t allocated_count = element_count / 2;

    std::cout << "2. Allocating " << allocated_count << " blocks (using pop() internally):\n";
    for (size_t i = 0; i < allocated_count; ++i) {
        blocks[i] = allocator.allocate(1);
        std::cout << "   - Allocated block " << i << " at address: " << static_cast<void*>(blocks[i]) << "\n";
    }
    std::cout << "   - Free list now has " << (element_count - allocated_count) << " blocks remaining\n\n";

    // Deallocate some blocks to show push() behavior (LIFO order)
    std::cout << "3. Deallocating blocks in reverse order (using push() internally):\n";
    for (size_t i = allocated_count; i > 0; --i) {
        size_t idx = i - 1;
        std::cout << "   - Deallocating block " << idx << " from address: " << static_cast<void*>(blocks[idx]) << "\n";
        allocator.deallocate(blocks[idx], 1);
    }
    std::cout << "   - Free list now has all " << element_count << " blocks again\n";
    std::cout << "   - Note: Blocks are pushed to head, so next allocation will return\n";
    std::cout << "     the most recently deallocated block (LIFO behavior)\n\n";

    // Demonstrate LIFO behavior
    std::cout << "4. Demonstrating LIFO behavior:\n";

    // Allocate two blocks
    int* block1 = allocator.allocate(1);
    int* block2 = allocator.allocate(1);
    std::cout << "   - Allocated block1: " << static_cast<void*>(block1) << "\n";
    std::cout << "   - Allocated block2: " << static_cast<void*>(block2) << "\n";

    // Deallocate them
    allocator.deallocate(block1, 1);
    allocator.deallocate(block2, 1);
    std::cout << "   - Deallocated block1 then block2\n";
    std::cout << "   - Free list head now points to block2 (last deallocated)\n";

    // Reallocate - should get block2 first (LIFO)
    int* new_block1 = allocator.allocate(1);
    int* new_block2 = allocator.allocate(1);
    std::cout << "   - Reallocated new_block1: " << static_cast<void*>(new_block1) << " (was block2)\n";
    std::cout << "   - Reallocated new_block2: " << static_cast<void*>(new_block2) << " (was block1)\n";
    std::cout << "   - This demonstrates LIFO: last deallocated is first allocated\n\n";

    // Clean up
    allocator.deallocate(new_block1, 1);
    allocator.deallocate(new_block2, 1);

    std::cout << "5. Summary:\n";
    std::cout << "   - push(): adds block to free list head (LIFO)\n";
    std::cout << "   - pop(): removes block from free list head\n";
    std::cout << "   - This provides fast O(1) allocation/deallocation\n";
    std::cout << "   - Cache-friendly: recently freed blocks are likely still in cache\n";
    std::cout << "============================================\n";
}

