    size_t current_pos = file.tell();

    // Get the actual file size to avoid reading beyond the file
    size_t file_size = file.size();
    size_t preview_size = (bytes_to_preview > file_size) ? file_size : bytes_to_preview;

    // Create a vector to hold the data
    std::vector<uint8_t> data(preview_size);

    // Read the data from file
    if (preview_size > 0) {
        file.read(data.data(), preview_size);
