```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer object
    hexi::file_buffer file;

    // Open the file for reading
    if (!file.open(file_path)) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Get the current read position to restore later
    size_t original_pos = file.tell();

    // Ensure we don't try to read beyond file size
    size_t file_size = file.size();
    size_t read_size = (header_size > file_size) ? file_size : header_size;

    // Create destination buffer
    std::vector<uint8_t> header_data(read_size);

    // Read the header data
    if (read_size > 0) {
        file.read(header_data.data(), read_size);
    }

    // Restore the original read position
    file.seek(original_pos);

    // Close the file
    file.close();

    return header_data;
}
```

