#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Create a non-const copy to call the serialise method
    UserData temp = data;
    temp.serialise(writer);
