#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write the length of the string as a prefix, then the string data
    writer.write(static_cast<uint32_t>(str.length()));
    writer.write(str.data(), str.length());
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the length prefix first
    uint32_t length;
    reader.read(length);

    // Read the string data based on the length
    std::string str;
    str.resize(length);
    reader.read(const_cast<char*>(str.data()), length);

    return str;
}
```

