Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    // Check if there are enough bytes to skip
    if (buffer.size() < bytes) {
        throw std::runtime_error("Not enough bytes in buffer to skip");
    }

    // Skip the specified number of bytes by consuming them
    buffer.consume(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header;

    // Check if there are enough bytes for the header (6 bytes: 2 for message_type + 4 for body_length)
    if (buffer.size() < sizeof(header.message_type) + sizeof(header.body_length)) {
        throw std::runtime_error("Not enough bytes in buffer for header");
    }

    // Read the message_type (2 bytes)
    header.message_type = static_cast<uint16_t>(buffer.read<uint8_t>() << 8);
    header.message_type |= static_cast<uint16_t>(buffer.read<uint8_t>());

    // Read the body_length (4 bytes)
    header.body_length = static_cast<uint32_t>(buffer.read<uint8_t>() << 24);
    header.body_length |= static_cast<uint32_t>(buffer.read<uint8_t>() << 16);
    header.body_length |= static_cast<uint32_t>(buffer.read<uint8_t>() << 8);
    header.body_length |= static_cast<uint32_t>(buffer.read<uint8_t>());

    // Check if there are enough bytes for the body
    if (buffer.size() < header.body_length) {
        throw std::runtime_error("Not enough bytes in buffer for body");
    }

    // Skip the body data
    buffer.consume(header.body_length);

    return header;
}
```

Alternative implementation using a more concise approach for reading multi-byte values:

```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::size_t bytes) {
    if (buffer.size() < bytes) {
        throw std::runtime_error("Not enough bytes in buffer to skip");
    }
    buffer.consume(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Check if there are enough bytes for the header
    constexpr std::size_t header_size = sizeof(uint16_t) + sizeof(uint32_t);
    if (buffer.size() < header_size) {
        throw std::runtime_error("Not enough bytes in buffer for header");
    }

    MessageHeader header;

    // Read message_type (big-endian)
    header.message_type = 0;
    for (int i = 0; i < sizeof(header.message_type); ++i) {
        header.message_type = (header.message_type << 8) | buffer.read<uint8_t>();
    }

    // Read body_length (big-endian)
    header.body_length = 0;
    for (int i = 0; i < sizeof(header.body_length); ++i) {
        header.body_length = (header.body_length << 8) | buffer.read<uint8_t>();
    }

    // Check if there are enough bytes for the body
    if (buffer.size() < header.body_length) {
        throw std::runtime_error("Not enough bytes in buffer for body");
    }

    // Skip the body data
    buffer.consume(header.body_length);

    return header;
}
```

Both implementations:

1. **skip_bytes_in_buffer**: Uses `buffer.consume()` to skip the specified number of bytes after validating there are enough bytes available.

2. **read_header_and_skip_body**: 
   - Reads the 2-byte `message_type` and 4-byte `body_length` from the buffer
   - Validates there are enough bytes for both the header and body
   - Uses `buffer.consume()` to skip the body data based on the length read from the header
   - Returns the populated `MessageHeader` structure

The second implementation is more concise and handles endianness consistently by reading multi-byte values in big-endian format.

