```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle negative values using zigzag encoding
    typename std::make_unsigned<T>::type zigzag_value;
    if (value < 0) {
        zigzag_value = static_cast<typename std::make_unsigned<T>::type>((-value) * 2 - 1);
    } else {
        zigzag_value = static_cast<typename std::make_unsigned<T>::type>(value * 2);
    }

    // Encode the zigzag value
    while (zigzag_value >= 0x80) {
        writer.write_byte(static_cast<std::uint8_t>((zigzag_value & 0x7F) | 0x80));
        zigzag_value >>= 7;
        bytes_written++;
    }

    writer.write_byte(static_cast<std::uint8_t>(zigzag_value));
    bytes_written++;

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    typename std::make_unsigned<T>::type result = 0;
    int shift = 0;

    while (true) {
        std::uint8_t byte = reader.read_byte();
        result |= static_cast<typename std::make_unsigned<T>::type>(byte & 0x7F) << shift;

        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            // Handle potential overflow
            break;
        }
    }

    // Convert from zigzag to signed
    if (result & 1) {
        return static_cast<T>(-(static_cast<typename std::make_signed<T>::type>(result >> 1) + 1));
    } else {
        return static_cast<T>(result >> 1);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Create buffer adaptor and writer
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(adaptor);

    // Encode the value
    encode_varint<T>(writer, original_value);

    // Create reader from the buffer
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    // Compare with original
    return original_value == decoded_value;
}
```

This implementation provides:

1. **`encode_varint`**: Uses zigzag encoding to handle both positive and negative integers efficiently. It writes bytes with the continuation bit set until the remaining value fits in 7 bits.

2. **`decode_varint`**: Reads bytes until it finds one without the continuation bit, then reconstructs the value and converts it back from zigzag encoding to a signed integer.

3. **`encode_decode_roundtrip`**: Creates a buffer, encodes the value, then decodes it and compares with the original to verify roundtrip correctness.

The zigzag encoding ensures that small negative numbers are encoded efficiently, and the implementation handles the variable-length nature of varint encoding properly.

