#include <hexi/exception.h>
#include <hexi/pmc/binary_stream.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        // Re-throw the current exception to catch and examine it
        throw;
    } catch (const hexi::pmc::stream_read_limit& e) {
        // Extract information from the stream_read_limit exception
        info.read_size = e.get_read_size();      // Size attempted to read
        info.total_read = e.get_total_read();    // Total bytes read so far
        info.read_limit = e.get_read_limit();    // The read limit that was exceeded
        info.occurred = true;
    } catch (...) {
        // Not a stream_read_limit exception
        info.occurred = false;
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream, void* destination, std::size_t length) {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        // Attempt to read from the stream
        stream.read(destination, length);
        info.occurred = false;  // Read succeeded, no exception occurred
    } catch (const hexi::pmc::stream_read_limit&) {
        // Catch stream_read_limit exception and extract information
        info = catch_stream_read_limit();
    } catch (...) {
        // Handle other types of exceptions
        info.occurred = false;
    }

    return info;
}

